```gdscript
extends Node

signal move_left, move_right, stop_movement

var speed = 70
var move_direction = Vector2.ZERO
var anim_player = get_node("PlayerAnim")

func _process(delta):
    if Input.is_action_pressed("left"):
        move_direction.x = -speed
    elif Input.is_action_pressed("right"):
